import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { Line } from 'react-chartjs-2';
import { Chart as ChartJS, CategoryScale, LinearScale, PointElement, LineElement, Title, Tooltip, Legend } from 'chart.js';
import { Cloud, TrendingUp, AlertTriangle, MapPin, Menu, LogOut, Mic } from 'lucide-react';

ChartJS.register(CategoryScale, LinearScale, PointElement, LineElement, Title, Tooltip, Legend);

function Dashboard({ user, onLogout, language, setLanguage }) {
  const [data, setData] = useState(null);
  const [selectedCrop, setSelectedCrop] = useState('Tomato');
  const [menuOpen, setMenuOpen] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    fetchDashboard();
  }, [selectedCrop]);

  const fetchDashboard = async () => {
    try {
      const res = await axios.get(`/api/dashboard/${user.id}?crop=${selectedCrop}&state=Maharashtra`);
      setData(res.data);
    } catch (error) {
      console.error('Error fetching dashboard:', error);
    }
  };

  if (!data) return <div className="flex items-center justify-center h-screen"><div className="text-2xl">Loading...</div></div>;

  const chartData = {
    labels: data.priceTrend.map(p => new Date(p.date).toLocaleDateString('en-IN', { month: 'short', day: 'numeric' })),
    datasets: [{
      label: 'Price (₹/quintal)',
      data: data.priceTrend.map(p => p.price),
      borderColor: 'rgb(34, 197, 94)',
      backgroundColor: 'rgba(34, 197, 94, 0.1)',
      tension: 0.4
    }]
  };

  return (
    <div className="min-h-screen pb-20">
      {/* Header */}
      <div className="bg-green-600 text-white p-4 sticky top-0 z-10 shadow-lg">
        <div className="flex justify-between items-center max-w-6xl mx-auto">
          <div>
            <h1 className="text-2xl font-bold">🌾 AGRICHAIN</h1>
            <p className="text-sm opacity-90">Welcome, {user.name}</p>
          </div>
          <div className="flex gap-2">
            <button onClick={() => window.speechSynthesis.speak(new SpeechSynthesisUtterance('Dashboard loaded'))} className="p-2 bg-white/20 rounded-lg">
              <Mic size={24} />
            </button>
            <button onClick={() => setMenuOpen(!menuOpen)} className="p-2 bg-white/20 rounded-lg">
              <Menu size={24} />
            </button>
          </div>
        </div>
      </div>

      {/* Menu Dropdown */}
      {menuOpen && (
        <div className="absolute right-4 top-16 bg-white rounded-lg shadow-xl p-4 z-20 w-48">
          <button onClick={() => navigate('/markets')} className="w-full text-left py-2 px-3 hover:bg-gray-100 rounded">Markets</button>
          <button onClick={() => navigate('/spoilage')} className="w-full text-left py-2 px-3 hover:bg-gray-100 rounded">Spoilage Risk</button>
          <button onClick={() => navigate('/recommendations')} className="w-full text-left py-2 px-3 hover:bg-gray-100 rounded">AI Recommendations</button>
          <hr className="my-2" />
          <button onClick={onLogout} className="w-full text-left py-2 px-3 hover:bg-red-100 text-red-600 rounded flex items-center gap-2">
            <LogOut size={16} /> Logout
          </button>
        </div>
      )}

      <div className="max-w-6xl mx-auto p-4 space-y-4">
        {/* Crop Selector */}
        <div className="card">
          <label className="block font-semibold mb-2">Select Crop</label>
          <select value={selectedCrop} onChange={(e) => setSelectedCrop(e.target.value)} className="input-field">
            <option>Tomato</option>
            <option>Onion</option>
            <option>Potato</option>
            <option>Wheat</option>
          </select>
        </div>

        {/* Weather Card */}
        <div className="card bg-gradient-to-r from-blue-500 to-blue-600 text-white">
          <div className="flex items-center justify-between">
            <div>
              <div className="flex items-center gap-2 mb-2">
                <Cloud size={32} />
                <span className="text-3xl font-bold">{data.weather.temp}°C</span>
              </div>
              <p className="text-lg">{data.weather.condition}</p>
              <p className="text-sm opacity-90">Humidity: {data.weather.humidity}%</p>
            </div>
            <div className="text-right">
              <p className="text-sm">3-Day Forecast</p>
              <div className="space-y-1 mt-2">
                {data.weather.forecast.map((f, i) => (
                  <div key={i} className="text-sm">{f.day}: {f.temp}°C</div>
                ))}
              </div>
            </div>
          </div>
        </div>

        {/* Price Trend */}
        <div className="card">
          <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
            <TrendingUp className="text-green-600" />
            7-Day Price Trend
          </h2>
          <Line data={chartData} options={{ responsive: true, plugins: { legend: { display: false } } }} />
          <div className="mt-4 flex justify-between text-center">
            <div>
              <p className="text-2xl font-bold text-green-600">₹{Math.round(data.summary.avgPrice)}</p>
              <p className="text-sm text-gray-600">Avg Price</p>
            </div>
            <div>
              <p className="text-2xl font-bold text-green-600">+{data.summary.change}%</p>
              <p className="text-sm text-gray-600">This Week</p>
            </div>
          </div>
        </div>

        {/* Quick Actions */}
        <div className="grid grid-cols-2 gap-4">
